class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.tokens = ["The", "quick", "brown", "fox", "jumps", "over", "the", "lazy"];
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }

    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = Math.max(500, this.container.clientHeight);
    }

    getSteps(inputs) {
        const vocabSize = 50257;
        return [
            {
                title: "Step 1: Tokenization",
                description: `Raw text is mapped to unique integers. For ${inputs.numTokens} tokens, the model looks up indices in a vocabulary of ${vocabSize.toLocaleString()} entries.`
            },
            {
                title: "Step 2: Vector Embedding",
                description: `Integers are converted into continuous vectors of size $d_{model}$. We add Positional Encodings so the model knows 'The' is at index 0 and 'quick' is at index 1.`
            },
            {
                title: "Step 3: Multi-Head Self-Attention",
                description: `Each token calculates how much 'attention' to pay to others. With **${inputs.numHeads} heads**, the model can track ${inputs.numHeads} different types of relationships simultaneously (e.g., grammar, subject-verb, semantics).`
            },
            {
                title: "Step 4: Feed Forward & Layer Norm",
                description: `The attention output is refined through a Multi-Layer Perceptron (MLP). This projects the contextual data into a higher abstract space to extract complex logic.`
            },
            {
                title: "Step 5: Output Logits & Softmax",
                description: `The final vector is projected back to the vocabulary size. At Temperature **${inputs.temperature}**, the probabilities are calculated. Lower temperature makes the model more confident/repetitive; higher makes it more diverse.`
            }
        ];
    }

    drawToken(x, y, text, isActive) {
        const ctx = this.ctx;
        ctx.fillStyle = isActive ? '#3b82f6' : '#1e293b';
        ctx.strokeStyle = '#64748b';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.roundRect(x - 40, y - 20, 80, 40, 8);
        ctx.fill();
        ctx.stroke();
        ctx.fillStyle = '#f8fafc';
        ctx.font = 'bold 14px Inter, system-ui';
        ctx.textAlign = 'center';
        ctx.fillText(text, x, y + 5);
    }

    drawVector(x, y, size, values) {
        const ctx = this.ctx;
        const cellH = 12;
        const cellW = 20;
        values.forEach((v, i) => {
            ctx.fillStyle = `rgba(59, 130, 246, ${0.2 + v * 0.8})`;
            ctx.fillRect(x - cellW / 2, y + i * cellH, cellW, cellH);
            ctx.strokeStyle = 'rgba(255,255,255,0.1)';
            ctx.strokeRect(x - cellW / 2, y + i * cellH, cellW, cellH);
        });
    }

    render(inputs, stepIndex) {
        const ctx = this.ctx;
        const w = this.canvas.width;
        const h = this.canvas.height;
        const { numTokens, embDim, temperature, numHeads } = inputs;

        ctx.clearRect(0, 0, w, h);
        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, w, h);

        const centerX = w / 2;
        const spacing = Math.min(w / (numTokens + 1), 100);
        const startX = centerX - (spacing * (numTokens - 1)) / 2;

        // Step 1: Tokenization
        if (stepIndex >= 0) {
            for (let i = 0; i < numTokens; i++) {
                this.drawToken(startX + i * spacing, 80, this.tokens[i % this.tokens.length], stepIndex === 0);
            }
        }

        // Step 2: Embeddings
        if (stepIndex >= 1) {
            for (let i = 0; i < numTokens; i++) {
                const vals = Array.from({ length: Math.min(embDim, 8) }, (_, k) => Math.abs(Math.sin(i * k + 1)));
                this.drawVector(startX + i * spacing, 120, embDim, vals);
                if (stepIndex === 1) {
                    ctx.strokeStyle = '#3b82f6';
                    ctx.beginPath();
                    ctx.moveTo(startX + i * spacing, 100);
                    ctx.lineTo(startX + i * spacing, 120);
                    ctx.stroke();
                }
            }
        }

        // Step 3: Attention
        if (stepIndex >= 2) {
            ctx.save();
            ctx.globalAlpha = stepIndex === 2 ? 1 : 0.3;
            for (let i = 0; i < numTokens; i++) {
                for (let j = 0; j < numTokens; j++) {
                    if (i === j) continue;
                    const strength = Math.abs(Math.cos(i * j * 0.5)) * 0.5;
                    ctx.beginPath();
                    ctx.strokeStyle = `rgba(147, 197, 253, ${strength})`;
                    ctx.lineWidth = strength * 5;
                    const cpX = (startX + i * spacing + startX + j * spacing) / 2;
                    const cpY = 280 + Math.abs(i - j) * 20;
                    ctx.moveTo(startX + i * spacing, 220);
                    ctx.quadraticCurveTo(cpX, cpY, startX + j * spacing, 220);
                    ctx.stroke();
                }
            }
            ctx.restore();
        }

        // Step 4: MLP / Transformer Block
        if (stepIndex >= 3) {
            const rectY = 320;
            ctx.fillStyle = stepIndex === 3 ? '#1e3a8a' : '#1e293b';
            ctx.strokeStyle = '#3b82f6';
            ctx.beginPath();
            ctx.roundRect(startX - 50, rectY, (numTokens - 1) * spacing + 100, 60, 10);
            ctx.fill();
            ctx.stroke();
            ctx.fillStyle = '#f8fafc';
            ctx.font = '12px monospace';
            ctx.textAlign = 'center';
            ctx.fillText('TRANSFORMER BLOCK (FFN + LAYER NORM)', centerX, rectY + 35);
        }

        // Step 5: Softmax
        if (stepIndex >= 4) {
            const barY = 420;
            const nextWords = ['dog', 'mat', 'car', 'tree', 'box'];
            const rawLogits = [10, 8, 3, 2, 1];

            // Temperature Scaling
            const scaledLogits = rawLogits.map(l => Math.exp(l / temperature));
            const sum = scaledLogits.reduce((a, b) => a + b, 0);
            const probs = scaledLogits.map(s => s / sum);

            probs.forEach((p, i) => {
                const barW = 60;
                const barH = p * 80;
                const bx = centerX - (barW * 2.5) + i * (barW + 10);

                ctx.fillStyle = i === 0 ? '#10b981' : '#3b82f6';
                ctx.fillRect(bx, barY - barH, barW, barH);

                ctx.fillStyle = '#f8fafc';
                ctx.font = '10px Inter';
                ctx.fillText(nextWords[i], bx + barW / 2, barY + 15);
                ctx.fillText((p * 100).toFixed(1) + '%', bx + barW / 2, barY - barH - 5);
            });

            ctx.fillStyle = '#f8fafc';
            ctx.textAlign = 'left';
            ctx.font = '12px Inter';
            ctx.fillText('Next Token Probabilities:', centerX - 180, barY - 100);
        }
    }
}
